const test = require("node:test");
const assert = require("node:assert");
const { total } = require("../src/cart.js");

test("no discount at or below 100", () => {
  assert.strictEqual(total([{ price: 50, qty: 1 }]), 50);
});

test("10% discount above 100", () => {
  assert.strictEqual(total([{ price: 60, qty: 2 }]), 108);
});
